// Agrupa os dados por indicador
const porIndicador = {};

for (const item of $input.all()) {
  const dados = item.json;
  const indicador = dados["Indicator Name"];

  if (!porIndicador[indicador]) {
    porIndicador[indicador] = [];
  }

  porIndicador[indicador].push({
    pais: dados["Country Name"],
    crescimento: parseFloat(dados["Crescimento_Percentual"]),
    valorInicial: parseFloat(dados["Valor_Inicial"]),
    valorFinal: parseFloat(dados["Valor_Final"])
  });
}

// Monta o resumo em texto
let resumo = "RESUMO DOS INDICADORES EDUCACIONAIS (1990-2017)\n\n";

for (const indicador in porIndicador) {
  const paises = porIndicador[indicador]
    .filter(p => !isNaN(p.crescimento))
    .sort((a, b) => b.crescimento - a.crescimento);

  const top5Maiores = paises.slice(0, 5);
  const top5Menores = paises.slice(-5).reverse();

  resumo += `--- ${indicador} ---\n`;
  resumo += "Top 5 maiores crescimentos:\n";
  top5Maiores.forEach(p => {
    resumo += `  ${p.pais}: ${p.valorInicial.toFixed(2)} -> ${p.valorFinal.toFixed(2)} (${p.crescimento.toFixed(1)}%)\n`;
  });
  resumo += "Top 5 menores crescimentos/quedas:\n";
  top5Menores.forEach(p => {
    resumo += `  ${p.pais}: ${p.valorInicial.toFixed(2)} -> ${p.valorFinal.toFixed(2)} (${p.crescimento.toFixed(1)}%)\n`;
  });
  resumo += "\n";
}

return [{ json: { resumo: resumo } }];

